const body = $input.first().json.body || $input.first().json;
const taskId = body.task_id || body.taskId || '';
const historyItems = body.history_items || [];
const statusItem = historyItems.find(h => h.field === 'status');
const newStatus = (statusItem?.after?.status || '').toLowerCase().trim();
return [{ json: { taskId, newStatus } }];

const task = $input.first().json;
const fields = task.custom_fields || [];

const getField = (id) => {
  const f = fields.find(f => f.id === id);
  if (!f) return '';
  if ((f.type === 'drop_down' || f.type === 'label') && f.type_config && f.type_config.options) {
    const opt = f.type_config.options.find(o => o.orderindex === f.value || String(o.id) === String(f.value));
    return opt ? opt.name : String(f.value != null ? f.value : '');
  }
  return String(f.value != null ? f.value : '');
};

const nome = (task.name || '').toUpperCase();
const cpf = getField('26b4ecd6-6963-4160-a554-30cd4f36a70c');
const rg = getField('f36e9cb0-f9d2-4cb8-91ea-e5014a2566c7');
const cnh_numero = getField('cbefb914-0e29-4611-b992-b689d0b0fbb1');
const cnh_categoria = getField('eda497ef-b8aa-4c1a-a512-3de5b7245aa3');
const endereco = getField('7eae45ba-94b4-4cb4-bd1b-927ef11b8107');
const numero_ait = getField('e220c08f-03dd-487a-a8a2-6cf25e5bf9d3');
const orgao_autuador = getField('6b771374-ef1b-42dd-af5a-ffb231e29112');
const uf_orgao = getField('20fe659f-9eef-4aa4-b170-a7e00cd687e8');
const valor_contrato = getField('b8647ffd-7a76-4790-90cf-8e6314e5e469');
const forma_pagamento = getField('be4fac1c-4178-4a0c-8315-69747e2af05f');

const now = new Date();
const dataBRT = now.toLocaleString('pt-BR', { timeZone: 'America/Fortaleza' });

const comentario = '\u{1F4CB} MF01 — BASE CONTRATUAL CONSOLIDADA\nData: ' + dataBRT + '\n—\nCliente: ' + nome + '\nCPF: ' + cpf + '\nRG: ' + rg + '\nCNH: ' + cnh_numero + ' / Cat: ' + cnh_categoria + '\nEndereco: ' + endereco + '\nAIT: ' + numero_ait + '\nOrgao: ' + orgao_autuador + ' / UF: ' + uf_orgao + '\nValor: ' + valor_contrato + '\nPagamento: ' + forma_pagamento + '\n—\n\u2705 Pronto para MF02 — Gerar Minuta';

return [{ json: { taskId: task.id, comentario } }];
